const results = $.steps.searchExisting.response.results || [];
const pages = results.filter(r => r.object === 'page').slice(0, 5).map(r => {
  let title = '';
  if (r.properties) {
    const titleProp = Object.values(r.properties).find(p => p.type === 'title');
    if (titleProp && titleProp.title && titleProp.title.length > 0) {
      title = titleProp.title.map(t => t.plain_text || '').join('');
    }
  }
  return { id: r.id, title: title || 'Untitled', url: r.url || '' };
});
let context = '';
pages.forEach((p, i) => {
  context += (i + 1) + '. ' + p.title + (p.url ? ' (' + p.url + ')' : '') + '\n';
});
return { existingPages: context, pageCount: pages.length };

const existing = $.steps.extractExisting.output;
const topic = $.input.topic;
const contentType = $.input.contentType || 'article';
const tone = $.input.tone || 'professional';

let prompt = 'You are a skilled content writer. Generate a ' + contentType + ' about the following topic in a ' + tone + ' tone.\n\n';
prompt += 'TOPIC: ' + topic + '\n\n';

if (existing.pageCount > 0) {
  prompt += 'EXISTING NOTION PAGES ON THIS TOPIC (for context, do not duplicate):\n';
  prompt += existing.existingPages + '\n';
  prompt += 'Build upon and complement the existing content. Do not repeat what already exists.\n\n';
}

prompt += 'CONTENT TYPE: ' + contentType + '\n';
prompt += 'TONE: ' + tone + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Generate well-structured content with clear headings and sections\n';
prompt += '- Each text block must be 1900 characters or fewer (Notion API limit)\n';
prompt += '- Include an introduction, main body with subsections, and conclusion\n';
prompt += '- Make it actionable and useful\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "page title",\n';
prompt += '  "summary": "one-sentence summary",\n';
prompt += '  "sections": [\n';
prompt += '    { "heading": "Section Title", "content": "section text under 1900 chars" }\n';
prompt += '  ],\n';
prompt += '  "tags": ["tag1", "tag2"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: $.input.topic, summary: 'Generated content', sections: [{ heading: 'Content', content: raw.slice(0, 1900) }], tags: [] }; }

const ai = $.steps.parseAI.output;
const blocks = [];

if (ai.summary) {
  blocks.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ text: { content: ai.summary.slice(0, 1900) } }] } });
  blocks.push({ object: 'block', type: 'divider', divider: {} });
}

(ai.sections || []).forEach(section => {
  if (section.heading) {
    blocks.push({ object: 'block', type: 'heading_2', heading_2: { rich_text: [{ text: { content: section.heading.slice(0, 1900) } }] } });
  }
  if (section.content) {
    const chunks = [];
    let remaining = section.content;
    while (remaining.length > 0) {
      chunks.push(remaining.slice(0, 1900));
      remaining = remaining.slice(1900);
    }
    chunks.forEach(chunk => {
      blocks.push({ object: 'block', type: 'paragraph', paragraph: { rich_text: [{ text: { content: chunk } }] } });
    });
  }
});

return { blocks, title: ai.title || $.input.topic, tags: ai.tags || [] };

const ai = $.steps.parseAI.output;
const pageResponse = $.steps.createNotionPage.response || {};
const pageUrl = pageResponse.url || '';
const title = $.steps.buildNotionBlocks.output.title;
const sectionCount = (ai.sections || []).length;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'New Notion Content Created', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Title:* ' + title + '\n*Type:* ' + ($.input.contentType || 'article') + ' | *Sections:* ' + sectionCount } });

if (ai.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:* ' + ai.summary } });
}

if (pageUrl) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':link: <' + pageUrl + '|View in Notion>' } });
}

if (ai.tags && ai.tags.length > 0) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Tags: ' + ai.tags.join(', ') + ' | Generated with Claude AI | One CLI' }] });
}

const fallback = 'New Notion page created: ' + title;
return { blocks, fallback };
